fn solve(n: i64, m: i64, k: i64) -> i64 {
    if k == 0 {
        return n * m;
    }
    if n == 1 && m == 1 {
        return 1;
    }
    let mut res = 0;
    let mut i = 0;
    while i < n {
        let mut j = 0;
        while j < m {
            let row = i + k;
            let col = j + k;
            if row >= n || col >= m {
                res += 1;
                break;
            }
            i = row + 1;
            j = col + 1;
        }
    }
    res
}
